import { BOARD_SIZE, type Board, type CellValue, type Direction, type GameSnapshot, type MoveResult, type RandomSource } from './types'

const WIN_TILE = 2048
const STARTING_TILES = 2

export function createEmptyBoard(): Board {
  return Array.from({ length: BOARD_SIZE }, () => Array<CellValue>(BOARD_SIZE).fill(null))
}

export function cloneBoard(board: Board): Board {
  return board.map((row) => [...row])
}

export function getEmptyCells(board: Board): Array<{ row: number; col: number }> {
  const emptyCells: Array<{ row: number; col: number }> = []

  for (let row = 0; row < BOARD_SIZE; row += 1) {
    for (let col = 0; col < BOARD_SIZE; col += 1) {
      if (board[row][col] === null) {
        emptyCells.push({ row, col })
      }
    }
  }

  return emptyCells
}

export function boardsEqual(a: Board, b: Board): boolean {
  return a.every((row, rowIndex) => row.every((value, columnIndex) => value === b[rowIndex][columnIndex]))
}

export function hasWinningTile(board: Board): boolean {
  return board.some((row) => row.some((value) => (value ?? 0) >= WIN_TILE))
}

export function canMove(board: Board): boolean {
  if (getEmptyCells(board).length > 0) {
    return true
  }

  for (let row = 0; row < BOARD_SIZE; row += 1) {
    for (let col = 0; col < BOARD_SIZE; col += 1) {
      const value = board[row][col]
      if (row + 1 < BOARD_SIZE && value === board[row + 1][col]) {
        return true
      }
      if (col + 1 < BOARD_SIZE && value === board[row][col + 1]) {
        return true
      }
    }
  }

  return false
}

export function spawnRandomTile(board: Board, random: RandomSource = Math.random): Board {
  const emptyCells = getEmptyCells(board)
  if (emptyCells.length === 0) {
    return cloneBoard(board)
  }

  const nextBoard = cloneBoard(board)
  const cellIndex = Math.floor(random() * emptyCells.length)
  const { row, col } = emptyCells[cellIndex]
  nextBoard[row][col] = random() < 0.9 ? 2 : 4
  return nextBoard
}

function slideAndMergeLine(line: Array<CellValue>): { line: Array<CellValue>; scoreGained: number } {
  const compacted = line.filter((value): value is number => value !== null)
  const merged: Array<CellValue> = []
  let scoreGained = 0

  for (let index = 0; index < compacted.length; index += 1) {
    const current = compacted[index]
    const next = compacted[index + 1]

    if (current === next) {
      const mergedValue = current * 2
      merged.push(mergedValue)
      scoreGained += mergedValue
      index += 1
    } else {
      merged.push(current)
    }
  }

  while (merged.length < BOARD_SIZE) {
    merged.push(null)
  }

  return { line: merged, scoreGained }
}

function reverseLine(line: Array<CellValue>): Array<CellValue> {
  return [...line].reverse()
}

function getColumn(board: Board, columnIndex: number): Array<CellValue> {
  return board.map((row) => row[columnIndex])
}

function setColumn(board: Board, columnIndex: number, values: Array<CellValue>): void {
  values.forEach((value, rowIndex) => {
    board[rowIndex][columnIndex] = value
  })
}

export function moveBoard(board: Board, direction: Direction, random: RandomSource = Math.random): MoveResult {
  const nextBoard = createEmptyBoard()
  let scoreGained = 0

  if (direction === 'left' || direction === 'right') {
    board.forEach((row, rowIndex) => {
      const oriented = direction === 'right' ? reverseLine(row) : [...row]
      const processed = slideAndMergeLine(oriented)
      scoreGained += processed.scoreGained
      nextBoard[rowIndex] = direction === 'right' ? reverseLine(processed.line) : processed.line
    })
  } else {
    for (let col = 0; col < BOARD_SIZE; col += 1) {
      const column = getColumn(board, col)
      const oriented = direction === 'down' ? reverseLine(column) : column
      const processed = slideAndMergeLine(oriented)
      scoreGained += processed.scoreGained
      setColumn(nextBoard, col, direction === 'down' ? reverseLine(processed.line) : processed.line)
    }
  }

  const moved = !boardsEqual(board, nextBoard)
  const spawnedBoard = moved ? spawnRandomTile(nextBoard, random) : cloneBoard(board)
  const won = hasWinningTile(spawnedBoard)
  const gameOver = !canMove(spawnedBoard)

  return {
    board: spawnedBoard,
    scoreGained,
    moved,
    won,
    gameOver,
  }
}

export function createInitialGame(random: RandomSource = Math.random): GameSnapshot {
  let board = createEmptyBoard()
  for (let count = 0; count < STARTING_TILES; count += 1) {
    board = spawnRandomTile(board, random)
  }

  return {
    board,
    score: 0,
    won: false,
    gameOver: false,
  }
}
