import { useCallback, useEffect, useMemo, useState } from 'react'
import './App.css'
import { GameBoard } from './components/GameBoard'
import { ScorePanel } from './components/ScorePanel'
import { createInitialGame, moveBoard } from './game/logic'
import type { Direction, GameSnapshot } from './game/types'

const KEY_TO_DIRECTION: Record<string, Direction> = {
  ArrowUp: 'up',
  ArrowDown: 'down',
  ArrowLeft: 'left',
  ArrowRight: 'right',
  w: 'up',
  a: 'left',
  s: 'down',
  d: 'right',
  W: 'up',
  A: 'left',
  S: 'down',
  D: 'right',
}

function getStatus(game: GameSnapshot): string {
  if (game.gameOver) return 'Game over! No more moves available.'
  if (game.won) return 'You reached 2048! Keep going if you want a bigger tile.'
  return 'Game in progress'
}

function App() {
  const [game, setGame] = useState<GameSnapshot>(() => createInitialGame())

  const handleRestart = useCallback(() => {
    setGame(createInitialGame())
  }, [])

  const handleMove = useCallback((direction: Direction) => {
    setGame((current) => {
      if (current.gameOver) {
        return current
      }

      const result = moveBoard(current.board, direction)
      if (!result.moved) {
        return current
      }

      return {
        board: result.board,
        score: current.score + result.scoreGained,
        won: current.won || result.won,
        gameOver: result.gameOver,
      }
    })
  }, [])

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const direction = KEY_TO_DIRECTION[event.key]
      if (!direction) {
        return
      }

      event.preventDefault()
      handleMove(direction)
    }

    window.addEventListener('keydown', onKeyDown)
    return () => window.removeEventListener('keydown', onKeyDown)
  }, [handleMove])

  const status = useMemo(() => getStatus(game), [game])

  return (
    <main className="app-shell">
      <div className="game-card">
        <ScorePanel score={game.score} status={status} onRestart={handleRestart} />
        <GameBoard board={game.board} />
      </div>
    </main>
  )
}

export default App
